// Find contacts with birthdays in next 7 days
const today = new Date();
const todayStr = today.toISOString().split('T')[0]; // YYYY-MM-DD

const contacts = $input.all();
const milestoneContacts = [];

for (const wrapper of contacts) {
  const c = wrapper.json;

  // Look for birthday custom field
  const bdayField = c.customFields?.find(f => 
    f.key === 'birthday' || 
    f.key === 'date_of_birth' || 
    f.key === 'dob'
  );
  if (!bdayField?.value) continue;

  const bday = new Date(bdayField.value);
  if (isNaN(bday.getTime())) continue;

  // Get birthday this year
  const thisYearBday = new Date(today.getFullYear(), bday.getMonth(), bday.getDate());

  // Calculate age
  const age = today.getFullYear() - bday.getFullYear();

  // Check if birthday is in next 7 days
  const msPerDay = 24 * 60 * 60 * 1000;
  const daysUntilBday = Math.round((thisYearBday - today) / msPerDay);

  // Normalize to positive (handle Jan birthdays from previous year)
  const adjustedDaysUntil = daysUntilBday < -180 ? daysUntilBday + 365 : daysUntilBday;

  if (adjustedDaysUntil >= 0 && adjustedDaysUntil <= 7) {
    // Determine milestone type
    let milestone = null;
    if (age + 1 === 65) milestone = 'Turning 65 - Medicare Eligible';
    else if (age + 1 === 70) milestone = 'Turning 70 - Final Expense Age';
    else if (age + 1 === 64) milestone = 'Pre-Medicare - 1 Year Away';
    else if ((age + 1) % 5 === 0) milestone = `Turning ${age + 1} - Milestone Birthday`;

    milestoneContacts.push({
      ...c,
      birthday: bdayField.value,
      birthdayThisYear: thisYearBday.toISOString().split('T')[0],
      age,
      daysUntil: adjustedDaysUntil,
      milestone,
      isTurning65: age + 1 === 65
    });
  }
}

return milestoneContacts;

